const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid request signature');
}

return [{ json: { hmac_valid: true } }];

const session = $input.first().json;

if (!session || !session.user_id) {
  throw new Error('Invalid or expired token');
}

const body = $('Receive Promote Request').first().json.body;

if (!body.session_id) throw new Error('session_id is required');
if (body.message_index === undefined) throw new Error('message_index is required');

if (!['owner', 'admin', 'staff'].includes(session.role)) {
  throw new Error('Insufficient permissions to promote');
}

return [{
  json: {
    user_id: session.user_id,
    role: session.role,
    client_id: session.client_id,
    slug: session.slug,
    session_id: body.session_id,
    message_index: body.message_index
  }
}];
